const API_BASE = process.env.NEXT_PUBLIC_API_URL || 'https://argmetrics.vercel.app/api/v1';
async function fetchAPI(endpoint, options) {
    const response = await fetch(`${API_BASE}${endpoint}`, {
        headers: {
            'Content-Type': 'application/json'
        },
        ...options
    });
    if (!response.ok) {
        throw new Error(`API Error: ${response.status} ${response.statusText}`);
    }
    return response.json();
}
async function getUSDRates() {
    return fetchAPI('/live/usd');
}
async function getHealth() {
    return fetchAPI('/health');
}
async function getMetrics(params) {
    const searchParams = new URLSearchParams();
    if (params) {
        Object.entries(params).forEach(([key, value])=>{
            if (value !== undefined) {
                searchParams.append(key, String(value));
            }
        });
    }
    const queryString = searchParams.toString();
    return fetchAPI(`/metrics${queryString ? `?${queryString}` : ''}`);
}
async function getMetricByName(name) {
    return fetchAPI(`/metrics/${name}`);
}
async function getCategories() {
    return fetchAPI('/metrics/categories');
}
async function getAvailableMetrics() {
    return fetchAPI('/metrics/available');
}
